library(shiny)
library(dplyr)
library(jsonlite)

# Workaround para Chromium Issue 468227 (descarga de CSV en shinylive)
downloadButton &lt;- function(...) {
  tag &lt;- shiny::downloadButton(...)
  tag$attribs$download &lt;- NULL
  tag
}

# ==========================================
# DEFINICIÓN DE RASGOS (Stearns 1992 + Arnold 1983)
# Fuente única: se usa tanto para construir la UI como para leer los inputs
# ==========================================
traits_def &lt;- list(
  tamano = list(label = "Tamaño corporal", choices = c("Pequeño", "Mediano", "Grande")),
  edad_madurez = list(label = "Edad a la madurez", choices = c("Temprana (&lt;1 año)", "Intermedia (1-5 años)", "Tardía (&gt;5 años)")),
  longevidad = list(label = "Longevidad estimada", choices = c("Corta (&lt;5 años)", "Media (5-20 años)", "Larga (&gt;20 años)")),
  crecimiento = list(label = "Tasa de crecimiento", choices = c("Lenta", "Moderada", "Rápida")),
  fecundidad = list(label = "Fecundidad por evento reproductivo", choices = c("Baja (1-2)", "Media (3-10)", "Alta (&gt;10)")),
  frecuencia_repro = list(label = "Frecuencia reproductiva", choices = c("Semélpara (una vez)", "Iterópara (varias veces)")),
  inversion_parental = list(label = "Inversión parental", choices = c("Baja", "Media", "Alta")),
  nutricion = list(label = "Modo nutricional", choices = c("Autótrofo", "Herbívoro", "Carnívoro", "Omnívoro", "Detritívoro")),
  rendimiento_locomotor = list(label = "Rendimiento locomotor", choices = c("Bajo", "Medio", "Alto")),
  tolerancia_termica = list(label = "Tolerancia térmica", choices = c("Estenoterma (rango estrecho)", "Euriterma (rango amplio)"))
)

generar_traits_ui &lt;- function(sufijo) {
  lapply(names(traits_def), function(id) {
    def &lt;- traits_def[[id]]
    selectInput(paste0(id, "_", sufijo), def$label, choices = def$choices)
  })
}

# ==========================================
# HELPERS
# ==========================================

# Reutilizado de bio-distribution.qmd: valida nombres contra el backbone de GBIF
gbif_name_match &lt;- function(name) {
  url &lt;- paste0("https://api.gbif.org/v1/species/match?name=", URLencode(name))
  tryCatch(fromJSON(url), error = function(e) NULL)
}

# mailto: identidad de contacto del proyecto (no personal), reutilizable en OSF/STAPLE
crossref_url &lt;- function(query, rows = 15) {
  paste0("https://api.crossref.org/works?query=", URLencode(query),
         "&rows=", rows, "&mailto=interdomestic@proton.me")
}

# Motor de unión: ¿el título/abstract de cada item menciona a las especies?
especies_en_texto &lt;- function(items, especie_a, especie_b) {
  if (is.null(items) || nrow(items) == 0) {
    return(list(ambas = logical(0), alguna = logical(0)))
  }
  texto &lt;- vapply(seq_len(nrow(items)), function(i) {
    titulo &lt;- tryCatch(paste(items$title[[i]], collapse = " "), error = function(e) "")
    abst &lt;- tryCatch(items$abstract[i], error = function(e) NA)
    abst &lt;- if (is.null(abst) || is.na(abst)) "" else abst
    tolower(paste(titulo, abst))
  }, character(1))
  menciona_a &lt;- grepl(tolower(especie_a), texto, fixed = TRUE)
  menciona_b &lt;- grepl(tolower(especie_b), texto, fixed = TRUE)
  list(ambas = menciona_a & menciona_b, alguna = menciona_a | menciona_b)
}

crossref_buscar &lt;- function(query, rows = 15) {
  tryCatch(fromJSON(crossref_url(query, rows))$message$items, error = function(e) NULL)
}

# Motor de unión de 3 niveles: nunca devuelve citas que no mencionen a ninguna especie
crossref_buscar_citas &lt;- function(especie_a, especie_b, rows = 15) {
  q_interaccion &lt;- paste(especie_a, especie_b,
                          "interaction OR predation OR competition OR mutualism OR parasitism OR facilitation")
  q_simple &lt;- paste(especie_a, especie_b)

  # Nivel 1: interacción + ambas especies mencionadas
  items1 &lt;- crossref_buscar(q_interaccion, rows)
  f1 &lt;- especies_en_texto(items1, especie_a, especie_b)
  if (!is.null(items1) && sum(f1$ambas) &gt;= 3) {
    return(list(items = items1[f1$ambas, , drop = FALSE],
                nivel = "interacciones bióticas, ambas especies mencionadas", consulta = q_interaccion))
  }

  # Nivel 2: sin palabras de interacción, ambas especies mencionadas
  items2 &lt;- crossref_buscar(q_simple, rows)
  f2 &lt;- especies_en_texto(items2, especie_a, especie_b)
  if (!is.null(items2) && sum(f2$ambas) &gt;= 1) {
    return(list(items = items2[f2$ambas, , drop = FALSE],
                nivel = "general, ambas especies mencionadas juntas", consulta = q_simple))
  }

  # Nivel 3: última red — al menos una especie mencionada, nunca ruido total
  base_items &lt;- if (!is.null(items1) && sum(f1$alguna) &gt; 0) items1 else items2
  base_f &lt;- if (!is.null(items1) && sum(f1$alguna) &gt; 0) f1 else f2
  if (!is.null(base_items) && sum(base_f$alguna) &gt;= 1) {
    return(list(items = base_items[base_f$alguna, , drop = FALSE],
                nivel = "baja confianza: mención de al menos una especie", consulta = q_simple))
  }

  list(items = NULL, nivel = "sin resultados que mencionen a ninguna de las dos especies", consulta = q_simple)
}

# Formatea cada item de Crossref como una cita legible
formatear_citas &lt;- function(items) {
  if (is.null(items) || nrow(items) == 0) return(character(0))
  vapply(seq_len(nrow(items)), function(i) {
    tryCatch({
      titulo &lt;- items$title[[i]]
      titulo &lt;- if (length(titulo) &gt; 0) titulo[1] else "Sin título"

      au &lt;- items$author[[i]]
      autores &lt;- if (is.null(au) || nrow(au) == 0) {
        "Autor/es no disponible/s"
      } else {
        nombres &lt;- paste(au$family, au$given, sep = ", ")
        if (length(nombres) &gt; 3) paste0(paste(nombres[1:3], collapse = "; "), " et al.")
        else paste(nombres, collapse = "; ")
      }

      anio &lt;- tryCatch(items$published[[i]]$`date-parts`[[1]][1], error = function(e) NA)
      revista &lt;- tryCatch(items$`container-title`[[i]][1], error = function(e) NA)
      doi &lt;- items$DOI[i]
      doi_url &lt;- if (!is.null(doi) && !is.na(doi)) paste0("https://doi.org/", doi) else NA

      paste0(
        autores, " (", ifelse(is.na(anio), "s.f.", anio), "). ", titulo,
        ifelse(!is.na(revista), paste0(". ", revista, "."), "."),
        ifelse(!is.na(doi_url), paste0(" ", doi_url), "")
      )
    }, error = function(e) "(No se pudo formatear esta cita.)")
  }, character(1))
}

# ==========================================
# UI
# ==========================================
ui &lt;- fluidPage(

  fluidRow(
    column(6, wellPanel(
      style = "background: #f8fafc; border: 1px solid #e2e8f0;",
      tags$h4("Especie A"),
      textInput("especie_a", "Nombre científico:", "Panthera onca"),
      generar_traits_ui("a")
    )),
    column(6, wellPanel(
      style = "background: #f8fafc; border: 1px solid #e2e8f0;",
      tags$h4("Especie B"),
      textInput("especie_b", "Nombre científico:", "Puma concolor"),
      generar_traits_ui("b")
    ))
  ),

  actionButton("verificar", "🔎 Verificar nombres antes de mapear",
               class = "btn-outline-info btn-sm"),
  uiOutput("validacion_nombres"),

  br(),
  actionButton("procesar", "Mapear Interacción", class = "btn-primary", style = "width: 100%;"),

  br(), br(),
  uiOutput("ficha_resultado"),

  br(),
  wellPanel(
    style = "background: #fafaf9; border: 1px solid #e7e5e4; font-size: 0.85em;",
    tags$strong("Fuentes y créditos:"),
    tags$p("La validación de nombres científicos usa el backbone taxonómico de GBIF.org. Las citas bibliográficas provienen de metadatos de Crossref (licencia CC BY 4.0 sobre los metadatos; los abstracts pueden estar sujetos a copyright de editoriales/autores). El marco de rasgos combina Stearns (1992) y Arnold (1983). La aplicación corre en su navegador vía Shiny (R) y shinylive/webR (WebAssembly), embebida con Quarto."),
    tags$div(
      style = "display: flex; gap: 8px; flex-wrap: wrap;",
      tags$a(href = "https://www.gbif.org", target = "_blank", class = "btn btn-sm btn-outline-secondary", "GBIF.org"),
      tags$a(href = "https://www.crossref.org", target = "_blank", class = "btn btn-sm btn-outline-secondary", "Crossref"),
      tags$a(href = "https://shiny.posit.co", target = "_blank", class = "btn btn-sm btn-outline-secondary", "Shiny"),
      tags$a(href = "https://posit-dev.github.io/r-shinylive/", target = "_blank", class = "btn btn-sm btn-outline-secondary", "shinylive / webR"),
      tags$a(href = "https://quarto.org", target = "_blank", class = "btn btn-sm btn-outline-secondary", "Quarto")
    )
  )
)

# ==========================================
# SERVIDOR
# ==========================================
server &lt;- function(input, output, session) {

  validacion &lt;- eventReactive(input$verificar, {
    list(
      a = list(consulta = input$especie_a, match = gbif_name_match(input$especie_a)),
      b = list(consulta = input$especie_b, match = gbif_name_match(input$especie_b))
    )
  })

  output$validacion_nombres &lt;- renderUI({
    v &lt;- validacion()
    tagList(lapply(list(v$a, v$b), function(r) {
      m &lt;- r$match
      if (is.null(m) || is.null(m$matchType) || m$matchType == "NONE") {
        div(class = "alert alert-danger", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("❌ '", r$consulta, "' no se encontró en el backbone de GBIF."))
      } else if (m$matchType == "EXACT") {
        div(class = "alert alert-success", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("✅ '", r$consulta, "' reconocido como ", m$scientificName, " (", m$status, ")"))
      } else {
        div(class = "alert alert-warning", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("⚠️ '", r$consulta, "' es una coincidencia aproximada. GBIF sugiere: ", m$canonicalName, "."))
      }
    }))
  })

  resumen_rasgos &lt;- function(sufijo) {
    paste(sapply(names(traits_def), function(id) {
      paste0(traits_def[[id]]$label, ": ", input[[paste0(id, "_", sufijo)]])
    }), collapse = " · ")
  }

  resultado &lt;- eventReactive(input$procesar, {
    req(input$especie_a, input$especie_b)
    withProgress(message = "Buscando citas en Crossref (motor de unión de 3 niveles)...", value = 0.3, {
      res &lt;- crossref_buscar_citas(input$especie_a, input$especie_b)
      incProgress(0.7)
      res
    })
  })

  output$ficha_resultado &lt;- renderUI({
    res &lt;- resultado()
    req(res)
    citas &lt;- formatear_citas(res$items)

    wellPanel(
      style = "background: #ffffff; border: 1px solid #d1d5db;",
      tags$h4("Ficha de Interacción"),
      tags$p(tags$strong("Especie A: "), input$especie_a),
      tags$p(style = "font-size: 0.85em; color: #64748b;", resumen_rasgos("a")),
      tags$p(tags$strong("Especie B: "), input$especie_b),
      tags$p(style = "font-size: 0.85em; color: #64748b;", resumen_rasgos("b")),
      tags$hr(),
      tags$pre(
        paste0(
          "--- METADATA PROFILE (FAIR/CARE) ---\n",
          "Fuente de citas: Crossref REST API\n",
          "Consulta ejecutada: ", res$consulta, "\n",
          "Nivel de resultados (motor de unión): ", res$nivel, "\n",
          "Citas encontradas: ", length(citas), "\n",
          "Fecha de consulta: ", format(Sys.time(), "%Y-%m-%d %H:%M %Z")
        )
      ),
      tags$hr(),
      if (length(citas) == 0) {
        tags$p("No se encontraron citas que mencionen a ninguna de las dos especies.")
      } else {
        tags$ol(lapply(citas, function(c) tags$li(HTML(c))))
      },
      br(),
      downloadButton("descargar_citas", "Descargar citas (.csv)", class = "btn-outline-secondary")
    )
  })

  output$descargar_citas &lt;- downloadHandler(
    filename = function() paste0("interdomestic_citas_", Sys.Date(), ".csv"),
    content = function(file) {
      res &lt;- resultado()
      req(res)
      citas &lt;- formatear_citas(res$items)
      df &lt;- data.frame(
        especie_a = input$especie_a,
        especie_b = input$especie_b,
        nivel_busqueda = res$nivel,
        cita = citas,
        stringsAsFactors = FALSE
      )
      write.csv(df, file, row.names = FALSE)
    }
  )
}

shinyApp(ui, server)

Distribución geográfica de especies: la co-existencia de especies en un espacio y tiempo brinda un marco regional para la ocurrencia de interacciones entre especies, incluyéndonos.
La co-existencia regional de especies forma un marco de co-evolución entre especies, o mosaico geográfico de co-evolución, en donde las especies evolucionan en función de las características de la interacción en el paisaje. La visualización de la distribución de especies de la vida silvestre, mediante mapas, ayuda en la interpretación multidisciplinar de la consulta.









⏳ Primera carga: el entorno estadístico (R) se descarga y arranca completo dentro de la ventana de tu navegador — puede tardar un minuto la primera vez. Después de esa carga inicial, la app responde al instante. ¡Gracias por la paciencia!









Tip💡 Cómo usar este apéndice interactivo






Escribe una o más especies, un nombre científico por línea (precargado con Panthera onca y Puma concolor como ejemplo).
Verifica los nombres con el botón “🔎 Verificar nombres” antes de sincronizar — se confirma si GBIF reconoce cada nombre tal cual, si hay una coincidencia aproximada, o si no lo encuentra (corregir nombre).
Define cuántos registros traer por especie con el campo “Registros máx.”
Aprieta “Sincronizar Distribución Geográfica” para consultar GBIF y ver los puntos de ocurrencia en el mapa — cada especie con su propio color.
Explorá el mapa (zoom, desplazamiento, popups con el nombre al hacer clic). Puedes descargar los datos crudos en .csv.










Importante🔎 Si dudas del nombre científico





Para que la búsqueda funcione bien, necesitas el nombre tal como lo reconoce el backbone taxonómico de GBIF. Si tienes dudas, verificalo antes en:

GBIF Species Search — la fuente misma que consulta esta app.
iNaturalist — identificación asistida por comunidad y por IA; puerta de entrada sugerida si solo tienes una foto o un nombre común.
Tropicos.org (Missouri Botanical Garden) — referencia nomenclatural para plantas.
Catalogue of Life — checklist taxonómico global de consenso, punto de partida para cualquier grupo.
Open Tree of Life — árbol filogenético navegable, mantenido activamente (el histórico Tree of Life Web Project está fuera de línea desde noviembre 2025).




A continuación se despliega el nodo modular de consulta biológica interactiva co-creado para el proyecto interdomestic, ejecutado mediante WebAssembly directamente en su navegador:
